// Rounding and Currency formatting
return items.map(item => {
  const out = { ...item.json };

  // Beneficio en porcentaje con 2 decimales
  if (out.beneficioPct !== undefined && out.beneficioPct !== null) {
    out.beneficioPctFmt = `${Number(out.beneficioPct).toFixed(2)}%`;
  }

  // ROI formateado (si existe array)
  if (Array.isArray(out.roi)) {
    out.roiFmt = out.roi.map(r => `${Number(r).toFixed(2)}%`);
  }

  // Stakes formateados (si existen)
  if (out.stakes) {
    out.stakesFmt = {};
    for (const [key, val] of Object.entries(out.stakes)) {
      out.stakesFmt[key] = `$${Number(val).toFixed(2)}`;
    }
  }

  // Cuotas formateadas
  if (out.best) {
    out.bestFmt = {
      home: `${out.best.home?.odds} (${out.best.home?.bookmaker})`,
      draw: `${out.best.draw?.odds} (${out.best.draw?.bookmaker})`,
      away: `${out.best.away?.odds} (${out.best.away?.bookmaker})`
    };
  }

  // Comentario IA (si existe)
  out.comentarioFmt = out.comentario || "Sin comentario IA";

  return { json: out };
});

// ValueCalc mejorado
return items.map((item, idx) => {
  let llmText = item.json.choices 
    ? item.json.choices[0].message.content 
    : item.json;

  // Normalizar a string
  try {
    llmText = typeof llmText === 'string' ? llmText.trim() : JSON.stringify(llmText);
  } catch(e){ llmText = "{}"; }

  // Probabilidades por defecto
  let prob = { local: 0.33, empate: 0.33, visitante: 0.34 };

  // Intentar parsear JSON del LLM
  try {
    const parsed = JSON.parse(llmText);
    if (parsed.prob) prob = parsed.prob;
    else if (parsed.local !== undefined) {
      prob = { local: Number(parsed.local), empate: Number(parsed.empate), visitante: Number(parsed.visitante) };
    }
  } catch(e){}

  // Obtener mejores cuotas
  const best = item.json.best || {};
  const valHome = (prob.local || 0) * (best.home?.odds || 0);
  const valDraw = (prob.empate || 0) * (best.draw?.odds || 0);
  const valAway = (prob.visitante || 0) * (best.away?.odds || 0);

  // Umbral configurable
  const threshold = 1.05;
  const valueBets = [];
  if (valHome > threshold) valueBets.push({ outcome: "home", valor: valHome, bookmaker: best.home?.bookmaker, cuota: best.home?.odds });
  if (valDraw > threshold) valueBets.push({ outcome: "draw", valor: valDraw, bookmaker: best.draw?.bookmaker, cuota: best.draw?.odds });
  if (valAway > threshold) valueBets.push({ outcome: "away", valor: valAway, bookmaker: best.away?.bookmaker, cuota: best.away?.odds });

  return {
    json: {
      match: item.json.match,
      prob,
      valueBets,
      best,
      stakes: item.json.stakes,
      beneficioPct: item.json.beneficioPct,
      roi: valueBets.map(v => (v.valor - 1).toFixed(2)), // ROI adicional
      confianzaIA: item.json.confianza || null // si el LLM devuelve confianza
    }
  };
});

// SurebetCalc robusto
const parseOdd = (v) => {
  if (v === null || v === undefined) return NaN;
  if (typeof v === 'number') return v;
  let s = String(v).trim();

  // 1) reemplazar coma decimal
  s = s.replace(',', '.');

  // 2) fraccional "3/2" -> 1 + 3/2 = 2.5 (decimal odds)
  if (/^\d+\/\d+$/.test(s)) {
    const [a,b] = s.split('/').map(Number);
    if (b === 0) return NaN;
    return 1 + (a / b);
  }

  // 3) americana "+150" / "-200"
  if (/^[+-]\d+$/.test(s)) {
    const n = Number(s);
    if (n > 0) return 1 + (n / 100);
    if (n < 0) return 1 + (100 / Math.abs(n));
  }

  // 4) probabilidad "0.45" o "45%" -> convertir a decimal odds
  if (s.endsWith('%')) {
    const p = parseFloat(s.slice(0, -1));
    if (!isFinite(p) || p <= 0) return NaN;
    return 100 / p;
  }
  const num = Number(s);
  if (isFinite(num)) {
    // si está entre 0 y 1, lo tratamos como probabilidad
    if (num > 0 && num < 1) return 1 / num;
    return num;
  }
  return NaN;
};

const round = (n, d=3) => Math.round(n * Math.pow(10,d)) / Math.pow(10,d);

return items.map(item => {
  const { match, best } = item.json || {};
  // debug: devolver best crudo si falta
  if (!best) {
    return { json: { match, error: 'best missing', raw: item.json } };
  }

  const cuotaHome = parseOdd(best?.home?.odds ?? best?.home ?? null);
  const cuotaDraw = parseOdd(best?.draw?.odds ?? best?.draw ?? null);
  const cuotaAway = parseOdd(best?.away?.odds ?? best?.away ?? null);

  const invalid = [cuotaHome, cuotaDraw, cuotaAway].some(v => !isFinite(v) || v <= 0);
  if (invalid) {
    return {
      json: {
        match,
        best,
        cuotaHome, cuotaDraw, cuotaAway,
        margen: null,
        surebet: false,
        beneficioPct: 0,
        stakes: null,
        capitalTotal: null,
        debug: 'Cuotas inválidas o no convertibles'
      }
    };
  }

  const invHome = 1 / cuotaHome;
  const invDraw = 1 / cuotaDraw;
  const invAway = 1 / cuotaAway;
  const margen = invHome + invDraw + invAway;
  const surebet = margen < 1;
  const beneficioPct = surebet ? (1 - margen) * 100 : 0;

  const CAPITAL_TOTAL = 100;
  const denom = invHome + invDraw + invAway;
  const stakeHome = (CAPITAL_TOTAL * invHome) / denom;
  const stakeDraw = (CAPITAL_TOTAL * invDraw) / denom;
  const stakeAway = (CAPITAL_TOTAL * invAway) / denom;

  return {
    json: {
      match,
      best,
      cuotaHome: round(cuotaHome,3),
      cuotaDraw: round(cuotaDraw,3),
      cuotaAway: round(cuotaAway,3),
      margen: round(margen,6),
      surebet,
      beneficioPct: round(beneficioPct,3),
      stakes: {
        home: round(stakeHome,2),
        draw: round(stakeDraw,2),
        away: round(stakeAway,2)
      },
      capitalTotal: CAPITAL_TOTAL
    }
  };
});

return items.map(item => {
  const match = item.json;
  const offers = match.offers;
  const best = { home: null, draw: null, away: null };

  offers.forEach(o => {
    const { bookmaker, odds, currency, url } = o;
    if (!best.home || odds.home > best.home.odds) best.home = { bookmaker, odds: odds.home, currency, url };
    if (!best.draw || odds.draw > best.draw.odds) best.draw = { bookmaker, odds: odds.draw, currency, url };
    if (!best.away || odds.away > best.away.odds) best.away = { bookmaker, odds: odds.away, currency, url };
  });

  return { json: { match: match.match, best } };
});

const arr = items.map(i => i.json);
const grouped = {};
arr.forEach(r => {
  if (!grouped[r.match]) grouped[r.match] = [];
  grouped[r.match].push(r);
});
return Object.keys(grouped).map(m => ({ json: { match: m, offers: grouped[m] } }));

// items = respuesta del HTTP Request
const raw = items[0].json;
const events = raw.events || [];
const currencyMap = {
  "Peru": "PEN",
  "Brazil": "BRL",
  "Argentina": "ARS",
  "Chile": "CLP",
  "South America": "PEN" // fallback regional
};

const normalized = events.flatMap(e => {
  const match = `${e.homeTeam} vs ${e.awayTeam}`;
  const timestamp = e.timestamp;
  const bookmakers = e.canonical?.bookmakers || {};

  return Object.keys(bookmakers).flatMap(bk => {
    const odds = bookmakers[bk].odds || {};
    const oneXtwo = odds["1X2"] || odds["1x2"] || null;
    if (!oneXtwo) return [];

    const currency = bookmakers[bk].currency 
              || currencyMap[e.country] 
              || "USD";

    return [{
      match,
      timestamp,
      league: e.league || null,   // 👈 agregado
      country: e.country || null, // 👈 agregado
      bookmaker: bk,
      market: "1X2",
      odds: { home: oneXtwo[0], draw: oneXtwo[1], away: oneXtwo[2] },
      url: bookmakers[bk].url || null,
      currency
    }];
  });
});

return normalized.map(r => ({ json: r }));

