return items.map(item => {
  const { match, best } = item.json;
  const hash = `${match}-${best.home.odds}-${best.draw.odds}-${best.away.odds}`;
  return { json: { ...item.json, hash } };
});

// AttachLastHash definitivo: detecta Hash en varias rutas y normaliza
return items.map(it => {
  const out = { ...it.json };

  // Helper para obtener valor por rutas posibles (soporta nested con '.')
  const getFirst = (obj, keys) => {
    for (const k of keys) {
      if (!k) continue;
      if (k.includes('.')) {
        const parts = k.split('.');
        let cur = obj;
        let ok = true;
        for (const p of parts) {
          if (cur && Object.prototype.hasOwnProperty.call(cur, p)) cur = cur[p];
          else { ok = false; break; }
        }
        if (ok && cur !== undefined) return cur;
      } else if (Object.prototype.hasOwnProperty.call(obj, k)) {
        return obj[k];
      }
    }
    return undefined;
  };

  // Posibles ubicaciones para el hash original y para el hash en Baserow
  const possibleOriginalHashKeys = ['hash','Hash','originalHash','_hash','fields.hash','fields.Hash'];
  const possibleBaserowHashKeys = ['lastHash','LastHash','last_hash','Hash','hash','fields.Hash','fields.hash','values.hash'];

  const rawHash = getFirst(out, possibleOriginalHashKeys);
  const rawLast = getFirst(out, possibleBaserowHashKeys);

  // Normalizar: strings -> trim + lowercase; 'null' o '' -> null
  const norm = v => {
    if (v === null || v === undefined) return null;
    if (typeof v === 'number') return String(v).trim().toLowerCase();
    if (typeof v === 'string') {
      const t = v.trim();
      if (t === '' || t.toLowerCase() === 'null') return null;
      return t.toLowerCase();
    }
    try { return String(v).trim().toLowerCase(); } catch(e) { return null; }
  };

  out._debug_rawHash = rawHash === undefined ? null : rawHash;
  out._debug_rawLast = rawLast === undefined ? null : rawLast;

  out.hash = norm(rawHash) || null;
  out.lastHash = norm(rawLast) || null;

  // Normalizar beneficioPct
  const bpRaw = out.beneficioPct ?? out.BeneficioPct ?? out.beneficio_pct ?? 0;
  out.beneficioPct = (bpRaw === null || bpRaw === '' || bpRaw === undefined) ? 0 : Number(bpRaw);

  // Resultado de comparación para debug
  out._exprResult = (() => {
    if (out.hash === null) return true;            // no hay hash calculado -> tratar como nuevo
    if (out.lastHash === null) return true;        // no hay lastHash -> nuevo
    return out.hash !== out.lastHash;              // distinto -> necesita acción
  })();

  return { json: out };
});

