const hour = Number(
  new Date().toLocaleString('en-US', {
    hour: 'numeric',
    hour12: false,
    timeZone: 'America/Lima'
  })
);

return [
  {
    json: {
      horaPeru: hour,
      dentroHorario: (hour >= 8 && hour < 20)
    }
  }
];

// Normalizar y serializar payload para enviar al LLM
return items.map(item => {
  const src = item.json || {};

  const getStr = (...keys) => {
    for (const k of keys) {
      if (src[k] !== undefined && src[k] !== null) {
        return String(src[k]);
      }
    }
    return "";
  };

  const getNum = (...keys) => {
    for (const k of keys) {
      const v = src[k];

      if (v === undefined || v === null) continue;

      const n = Number(v);

      if (!Number.isNaN(n)) return n;
    }

    return null;
  };

  const match = getStr("Match", "match");
  const league = getStr("League", "league");
  const country = getStr("Country", "country");

  const timestamp =
    getStr("LastUpdated", "timestamp") ||
    new Date().toISOString();

  const hash =
    getStr("hash", "_debug_rawHash") || "";

  const bestSrc = src.best || src.odds || {};

  const homeOdds =
    bestSrc?.home?.odds ||
    getNum("homeOdds", "home");

  const drawOdds =
    bestSrc?.draw?.odds ||
    getNum("drawOdds", "draw");

  const awayOdds =
    bestSrc?.away?.odds ||
    getNum("awayOdds", "away");

  const normalized = {
    match,
    league,
    country,
    timestamp,
    hash,
    best: {
      home: {
        odds: homeOdds || null
      },
      draw: {
        odds: drawOdds || null
      },
      away: {
        odds: awayOdds || null
      }
    }
  };

  const hasOdds =
    normalized.best.home.odds &&
    normalized.best.draw.odds &&
    normalized.best.away.odds;

  item.json.normalized = normalized;

  // Ya no falla
  item.json.payloadString =
    JSON.stringify(normalized);

  item.json.skipLLM = !hasOdds;

  return item;
});

// Function: parsear salida LLM y normalizar (robusto para múltiples items)
return items.map(item => {
  // Ajusta según dónde el LLM deje la respuesta
  const rawCandidate =
    item.json.choices?.[0]?.message?.content ||
    item.json.llmText ||
    item.json.response ||
    item.json.text ||
    null;

  let parsed = null;
  if (rawCandidate) {
    try {
      parsed = (typeof rawCandidate === 'string') ? JSON.parse(rawCandidate.trim()) : rawCandidate;
    } catch (e) {
      // intentar extraer JSON dentro de texto (por si el LLM añadió texto extra)
      try {
        const maybeJson = rawCandidate.match(/\{[\s\S]*\}$/);
        parsed = maybeJson ? JSON.parse(maybeJson[0]) : null;
      } catch (e2) {
        parsed = null;
      }
    }
  }

  // Valores por defecto si parsed es null o no tiene campos esperados
  const llm = {
    tipo: parsed?.tipo || "ninguno",
    riesgo: parsed?.riesgo || "medio",
    confianza: Number(parsed?.confianza ?? 0),
    comentario: parsed?.comentario || (parsed ? JSON.stringify(parsed).slice(0,120) : "LLM inválido o no parseable"),
    raw: rawCandidate || null
  };

  // Mantener el origen para los siguientes nodos
  return { json: { llm, src: item.json } };
});
